76	  const size_t num_bytes_available =
77	      (written_address - read_address) % m_buffer_size_bytes;
78	
79	  if (num_bytes_available < min_num_bytes) {
80	    // Note that 'num_bytes_available' can be zero sometimes even if we got
81	    // the 'write_done' interrupt, depending on the timing of things.
82	    // If in the previous round we got and cleared the interrupt,
83	    // but a new write finished before we read the 'written_address'.
84	    // In that case we would read and process all the data, but the interrupt
85	    // would still have triggered again and triggered another entry into this
