103	    result_num_bytes = std::min(max_num_bytes_to_read_out, num_bytes_until_end);
104	  } else {
105	    // Read as much data as we can.
106	    // We have guaranteed 'max_num_bytes_to_read_out' of continuous data.
107	    result_num_bytes = max_num_bytes_to_read_out;
108	  }
